INSERT INTO `careers` (`id`, `name`, `location`, `salary`, `description`, `content`, `status`, `created_at`, `updated_at`) VALUES
(2, 'Trưởng nhóm phát triển FullStack', 'Tòa C2-D\'.Capitable KDT Đông Nam, Đường Trần Duy Hưng,P.Trung Hòa,Q.Cầu Giấy,TP.Hà Nội', '986', 'Cơ hội hấp dẫn cho một Trưởng nhóm phát triển phần mềm để lãnh đạo nhóm phát triển phần mềm của chúng tôi trong việc xây dựng các hệ thống mạnh mẽ và có khả năng mở rộng.', '<p>Đang cập nhật dữ liệu …..</p>', 'published', '2024-12-09 00:01:27', '2025-06-06 10:13:18'),
(3, 'Nhà thiết kế UI/UX', 'Tòa C2-D\'.Capitable KDT Đông Nam, Đường Trần Duy Hưng,P.Trung Hòa,Q.Cầu Giấy,TP.Hà Nội', '0', 'Chúng tôi đang tìm kiếm một Nhà thiết kế UI/UX tài năng để tạo ra trải nghiệm người dùng trực quan và ấn tượng cho các sản phẩm của chúng tôi.', '<p>Đang cập nhật dữ liệu….</p>', 'published', '2024-12-09 00:01:27', '2025-04-15 02:40:47'),
(4, 'Quản lý sản phẩm', 'Tòa C2-D\'.Capitable KDT Đông Nam, Đường Trần Duy Hưng,P.Trung Hòa,Q.Cầu Giấy,TP.Hà Nội', '0', 'Với tư cách là Quản lý sản phẩm, bạn sẽ thúc đẩy quá trình phát triển và chiến lược của các sản phẩm để đáp ứng nhu cầu của lượng người dùng ngày càng tăng.', '<p>Đang cập nhật dữ liệu …….</p>', 'published', '2024-12-09 00:01:27', '2025-04-15 02:40:58'),
(5, 'Nhà khoa học dữ liệu', 'Tòa C2-D\'.Capitable KDT Đông Nam, Đường Trần Duy Hưng,P.Trung Hòa,Q.Cầu Giấy,TP.Hà Nội', '0', 'Đang tìm Nhà khoa học dữ liệu để phân tích các tập dữ liệu lớn và đưa ra thông tin chi tiết có thể hành động được để đưa ra quyết định kinh doanh.', '<p>Đang cập nhật dữ liệu ……</p>', 'published', '2024-12-09 00:01:27', '2025-04-15 02:41:05'),
(6, 'Kỹ sư DevOps', 'Tòa C2-D\'.Capitable KDT Đông Nam, Đường Trần Duy Hưng,P.Trung Hòa,Q.Cầu Giấy,TP.Hà Nội', '0', 'Chúng tôi đang tuyển dụng một Kỹ sư DevOps để hợp lý hóa quy trình phát triển và đảm bảo độ tin cậy cũng như khả năng mở rộng của cơ sở hạ tầng.', '<p>Đang cập nhật JobDescriptions</p>', 'published', '2024-12-09 00:01:27', '2025-04-15 02:41:13');
INSERT INTO `careers_translations` (`lang_code`, `careers_id`, `name`, `location`, `salary`, `description`, `content`) VALUES
('en_US', 2, 'Fullstack development team leader', 'C2-D\'.Capitable KDT Court, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi City', '986', 'Attractive opportunities for a software development team leader to lead our software development team in building strong and expandable systems.', '<p>Updating data ... ..</p>'),
('en_US', 3, 'UI/UX Designer', 'C2-D\'.Capitable KDT Court, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi City', '0', 'We are looking for a talented UI/UX designer to create a visual and impressive user experience for our products.', '<p>Đang cập nhật dữ liệu….</p>'),
('en_US', 4, 'Product management', 'C2-D\'.Capitable KDT Court, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi City', '0', 'As a product management, you will promote the development and strategy of products to meet the needs of the increasing number of users.', '<p>Đang cập nhật dữ liệu …….</p>'),
('en_US', 5, 'Data scientist', 'C2-D\'.Capitable KDT Court, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi City', '0', 'Looking for data scientists to analyze large data sets and give detailed information that can be acting to make business decisions.', '<p>Đang cập nhật dữ liệu ……</p>'),
('en_US', 6, 'Devops engineer', 'C2-D\'.Capitable KDT Court, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi City', '0', 'We are recruiting a Devops engineer to streamline the development process and ensure the reliability as well as the expansion of the infrastructure.', '<p>Đang cập nhật JobDescriptions</p>');
