INSERT INTO `faqs` (`id`, `question`, `answer`, `category_id`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Tôi có thể xem bản demo trước khi mua dịch vụ kinh doanh của bạn không?', '<p><span style=\"color:rgb(37,37,37);\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Chắc chắn rồi! Chúng tôi hiểu rằng việc chứng kiến ​​các dịch vụ của chúng tôi hoạt động có thể hữu ích. Trong hầu hết các trường hợp, chúng tôi có thể cung cấp bản demo hoặc tư vấn miễn phí để giới thiệu năng lực của mình và đảm bảo chúng phù hợp với nhu cầu cụ thể của bạn.</span> </span></p>', 3, 'published', '2024-12-09 00:01:27', '2025-07-02 09:27:39'),
(2, 'Bạn cung cấp những hình thức thanh toán nào cho các dịch vụ kinh doanh của mình?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Chúng tôi cung cấp các gói thanh toán linh hoạt để đáp ứng các ngân sách kinh doanh khác nhau. Chúng tôi có thể cung cấp các khoản thanh toán trả trước, trả góp hàng tháng hoặc giá theo dự án tùy thuộc vào dịch vụ. Hãy thoải mái thảo luận về tùy chọn thanh toán ưa thích của bạn với nhóm bán hàng của chúng tôi để tìm giải pháp tốt nhất cho bạn.</span></span></p>', 4, 'published', '2024-12-09 00:01:27', '2025-04-14 08:39:09'),
(3, 'Thời gian xử lý dịch vụ kinh doanh của bạn là bao lâu?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Thời gian hoàn thành có thể thay đổi tùy thuộc vào mức độ phức tạp của dịch vụ và nhu cầu cụ thể của bạn. Chúng tôi sẽ cung cấp mốc thời gian rõ ràng trong giai đoạn tham vấn hoặc đề xuất ban đầu. Chúng tôi cũng ưu tiên giao tiếp cởi mở và cập nhật cho bạn trong suốt quá trình.</span></span></p>', 4, 'published', '2024-12-09 00:01:27', '2025-04-14 08:38:48'),
(4, 'Bạn có cung cấp bất kỳ đảm bảo hay bảo hành nào cho các dịch vụ kinh doanh của mình không?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Chúng tôi đảm bảo chất lượng công việc của mình và cung cấp sự đảm bảo về sự hài lòng cho nhiều dịch vụ của chúng tôi. Các điều khoản cụ thể sẽ được nêu trong thỏa thuận của chúng tôi. Nếu bạn có bất kỳ thắc mắc nào, đừng ngần ngại yêu cầu làm rõ.</span></span></p>', 1, 'published', '2024-12-09 00:01:27', '2025-04-14 08:36:42'),
(5, 'Các thành viên trong nhóm của bạn có trình độ hoặc chứng chỉ gì?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Đội ngũ của chúng tôi bao gồm các chuyên gia giàu kinh nghiệm và trình độ. Chúng tôi đầu tư vào đào tạo liên tục để đảm bảo chúng tôi luôn cập nhật các xu hướng mới nhất và các thông lệ tốt nhất của ngành. Hãy thoải mái tìm hiểu về các chứng chỉ hoặc chuyên môn cụ thể có liên quan đến nhu cầu của bạn.</span></span></p>', 4, 'published', '2024-12-09 00:01:27', '2025-04-14 08:38:28'),
(6, 'Làm thế nào để đảm bảo an toàn dữ liệu của tôi khi sử dụng dịch vụ kinh doanh của bạn?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Bảo mật dữ liệu là ưu tiên hàng đầu của chúng tôi. Chúng tôi sử dụng các biện pháp bảo mật mạnh mẽ để bảo vệ thông tin của bạn, bao gồm máy chủ an toàn, giao thức mã hóa và kiểm soát truy cập. Chúng tôi có thể cung cấp thêm thông tin chi tiết về các hoạt động bảo mật của mình theo yêu cầu.</span></span></p>', 4, 'published', '2024-12-09 00:01:27', '2025-04-14 08:38:04'),
(7, 'Tôi có thể tùy chỉnh dịch vụ kinh doanh của bạn để phù hợp với nhu cầu cụ thể của mình không?', '<div class=\"gtx-body\" style=\"color:rgb(37,37,37);font-family:Roboto, arial, sans-serif;font-size:18px;font-style:normal;font-weight:400;margin:5px auto;padding:5px 0px;word-spacing:0px;\">Có, tùy chỉnh thường có thể thực hiện được. Chúng tôi hiểu rằng mỗi doanh nghiệp là duy nhất. Chúng tôi dành thời gian để hiểu các yêu cầu của bạn và điều chỉnh các dịch vụ của mình để mang lại kết quả tốt nhất có thể cho tình huống cụ thể của bạn.</div><p><br> </p>', 1, 'published', '2024-12-09 00:01:27', '2025-04-14 08:37:19'),
(8, 'Làm thế nào tôi có thể nhận được báo giá cho dịch vụ kinh doanh của bạn?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Nhận báo giá thật dễ dàng! Chỉ cần liên hệ với chúng tôi qua trang web, email hoặc điện thoại. Chúng tôi sẽ thảo luận về nhu cầu của bạn và cung cấp báo giá được cá nhân hóa dựa trên dịch vụ đã chọn và phạm vi của dịch vụ đó.</span></span></p>', 5, 'published', '2024-12-09 00:01:27', '2025-04-14 08:37:00'),
(9, 'Sự khác biệt giữa các gói dịch vụ kinh doanh của bạn là gì?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Chúng tôi cung cấp nhiều gói dịch vụ khác nhau để đáp ứng các nhu cầu và ngân sách kinh doanh khác nhau. Mỗi gói thường bao gồm một bộ tính năng hoặc sản phẩm cụ thể. Chúng tôi rất vui lòng giải thích sự khác biệt và đề xuất lựa chọn tốt nhất cho bạn trong quá trình tư vấn.</span></span></p>', 1, 'published', '2024-12-09 00:01:27', '2025-04-14 08:36:21'),
(10, 'Bạn có cung cấp hỗ trợ liên tục nào sau khi tôi mua dịch vụ kinh doanh của bạn không?', '<div class=\"gtx-body\" style=\"color:rgb(37,37,37);font-family:Roboto, arial, sans-serif;font-size:18px;font-style:normal;font-weight:400;margin:5px auto;padding:5px 0px;word-spacing:0px;\">Có, chúng tôi cung cấp hỗ trợ liên tục để đảm bảo bạn tận dụng tối đa các dịch vụ của chúng tôi. Điều này có thể bao gồm tài liệu đào tạo, quyền truy cập vào bộ phận trợ giúp hoặc thậm chí là các buổi tư vấn bổ sung tùy thuộc vào dịch vụ.</div><p><br> </p>', 3, 'published', '2024-12-09 00:01:27', '2025-04-14 08:37:44');
INSERT INTO `faqs_translations` (`lang_code`, `faqs_id`, `question`, `answer`) VALUES
('en_US', 1, 'Can I see a demo before purchasing your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Absolutely! We understand that seeing our services in action can be helpful. In most cases, we can provide a free demo or consultation to showcase our capabilities and ensure they are suitable for your specific needs.</span></span></p>'),
('en_US', 2, 'What forms of payment do you offer for your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">We offer flexible payment plans to accommodate different business budgets. We can offer upfront payments, monthly installments or project pricing depending on the service. Feel free to discuss your preferred payment option with our sales team to find the best solution for you.</span></span></p>'),
('en_US', 3, 'How long does it take to process your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Completion times can vary depending on the complexity of the service and your specific needs. We will provide a clear timeline during the initial consultation or proposal stage. We also prioritize open communication and keeping you updated throughout the process.</span></span></p>'),
('en_US', 4, 'Do you offer any guarantees or warranties for your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">We guarantee the quality of our work and offer satisfaction guarantees on many of our services. Specific terms will be outlined in our agreement. If you have any questions, please do not hesitate to ask for clarification.</span></span></p>'),
('en_US', 5, 'What qualifications or certifications do your team members have?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Our team consists of experienced and qualified professionals. We invest in ongoing training to ensure we stay up to date with the latest trends and industry best practices. Feel free to inquire about specific certifications or specializations that are relevant to your needs.</span></span></p>'),
('en_US', 6, 'How do I ensure the safety of my data when using your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Data security is our top priority. We use robust security measures to protect your information, including secure servers, encryption protocols, and access controls. We can provide more details about our security practices upon request.</span></span></p>'),
('en_US', 7, 'Can I customize your business services to fit my specific needs?', '<p>Yes, customization is often possible. We understand that every business is unique. We take the time to understand your requirements and tailor our services to deliver the best possible results for your specific situation.</p>'),
('en_US', 8, 'How can I get a quote for your business services?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Getting a quote is easy! Just contact us via our website, email or phone. We will discuss your needs and provide you with a personalized quote based on the service you have chosen and its scope.</span></span></p>'),
('en_US', 9, 'What is the difference between your business service packages?', '<p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">We offer a variety of service packages to meet different business needs and budgets. Each package typically includes a specific set of features or products. We are happy to explain the differences and recommend the best option for you during your consultation.</span></span></p>');
