(1, 'Trang chủ', '<shortcode>[simple-slider style=\"style-2\" key=\"home-silde\"][/simple-slider]</shortcode><shortcode>[site-statistics style=\"style-1\" quantity=\"4\" title_1=\"Các dự án đã hoàn thành\" data_1=\"45\" unit_1=\"+\" image_1=\"icons/trophy.png\" title_2=\"Khách hàng hài lòng 100%\" data_2=\"92\" unit_2=\"K\" image_2=\"icons/star.png\" title_3=\"Chúng tôi luôn sẵn sàng hỗ trợ khắp thế giới\" data_3=\"19\" unit_3=\"+\" image_3=\"icons/popularity.png\" title_4=\"Số năm điều hành công ty\" data_4=\"25\" unit_4=\"+\" image_4=\"icons/time.png\" background_image=\"backgrounds/site-statistics-bg.png\" background_color=\"#FFFBF3\" enable_lazy_loading=\"yes\"][/site-statistics]</shortcode><shortcode>[services style=\"style-5\" title=\"Sản phẩm tốt nhất &lt;br&gt; Cho doanh nghiệp của bạn\" subtitle=\"CHÚNG TÔI CUNG CẤP NHỮNG GÌ\" service_ids=\"1,2,3,4,5,6\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/services]</shortcode><shortcode>[include-webdemo][/include-webdemo]</shortcode><shortcode>[testimonials style=\"style-2\" title=\"Khách hàng của chúng tôi nói gì\" subtitle=\"LỜI CHỨNG THỰC CỦA KHÁCH HÀNG\" testimonial_ids=\"1,2,3,4\" background_color=\"rgb(207, 226, 243)\" enable_lazy_loading=\"yes\"][/testimonials]</shortcode><shortcode>[about-us-information style=\"style-6\" title=\"Chúng tôi cung cấp các giải pháp công nghệ toàn diện cho doanh nghiệp của bạn\" subtitle=\"VỀ CÔNG TY CHÚNG TÔI\" description=\"Hisotech mang đến các giải pháp công nghệ hiện đại, tối ưu cho doanh nghiệp trong kỷ nguyên số. Chúng tôi kết hợp giữa tư duy sáng tạo và kỹ thuật tiên tiến để tạo nên giá trị bền vững. Đội ngũ của Hisotech không ngừng đổi mới, cam kết đồng hành cùng khách hàng trên hành trình chuyển đổi số toàn diện.\" image=\"014bbcf8b05aef017c85102b68dbd37e.jpg\" image_1=\"1179ca0d343a36376df117e5056144ab-1.jpg\" image_2=\"dd8d2bb106af8281dc33d9066ac2b53d-1.jpg\" quantity=\"2\" title_1=\"Nhóm hỗ trợ\" description_1=\"Chúng tôi hỗ trợ 24/7 các vấn đề yêu cầu của bạn\" icon_1=\"ti ti-24-hours\" title_2=\"Chuyên gia\" description_2=\"Gặp gỡ, trao đổi với các chuyên gia về vấn đề của bạn\" icon_2=\"ti ti-report-money\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[contact-block style=\"style-3\" title=\"Chúng tôi cung cấp những giải pháp công nghệ chuyên biệt, phù hợp cho tất cả doanh nghiệp\" subtitle=\"Cải tiến doanh nghiệp của bạn bằng cách liên hệ ngay với chúng tôi\" button_label=\"Xem tất cả dịch vụ\" button_url=\"/services\" background_image=\"backgrounds/contact-block-bg-3-1.png\" background_color=\"rgb(20, 23, 108)\" enable_lazy_loading=\"yes\"][/contact-block]</shortcode><shortcode>[team style=\"style-5\" title=\"Gặp gỡ đội ngũ của chúng tôi\" subtitle=\"Chuyên viên kỹ thuật\" team_ids=\"1,2,3,4\" button_label=\"Liên hệ với chúng tôi\" button_url=\"/contact-us\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/team]</shortcode><shortcode>[faqs title=\"Câu hỏi thường gặp\" description=\"Quyền tự do lựa chọn của chúng ta là không bị giới hạn, và khi không có gì ngăn cản ta làm điều mình yêu thích nhất, mọi niềm vui đều trở nên trong tầm tay.\" image=\"7c3e8109104a75c1f23384a8aaa37837.jpg\" faq_category_ids=\"1,2,3\" limit=\"3\" floating_block_icon=\"ti ti-24-hours\" floating_block_title=\"Bạn cần giúp đỡ ?\" floating_block_description=\"Cảm thấy tò mò? Hãy đọc qua một số Câu Hỏi Thường Gặp của chúng tôi hoặc liên hệ với đội ngũ Hỗ Trợ để được giúp đỡ.\" enable_lazy_loading=\"yes\"][/faqs]</shortcode><shortcode>[about-us-information style=\"style-14\" title=\"Bạn muốn trao đổi với chuyên gia\" description=\"Chúng tôi xử lý hiệu quả các nhiệm vụ với độ phức tạp khác nhau, cung cấp các cam kết dài hạn và không ngừng nâng cao chuyên môn.\" image=\"8d0c4f7a3b8d936f6a83385e47e72e2a.jpg\" quantity=\"3\" title_1=\"Đồng hành cùng doanh nghiệp\" title_2=\"Phân tích và nghiên cứu\" title_3=\"Nhanh chóng, tiện lợi\" button_label=\"Xem thêm\" button_url=\"/contact-us\" background_color=\"rgb(236, 246, 250)\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[blog-posts style=\"style-1\" category_ids=\"2,3,4,5\" title=\"Tin tức nổi bật và thông tin\" subtitle=\"BÀI VIẾT MỚI CẬP NHẬT\" limit=\"3\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/blog-posts]</shortcode>', 1, 'logo/icon.png', 'homepage', 'Trang chủ Hisotech Group, Hisotech, HisotechGroup', 'published', '2024-12-09 00:01:18', '2025-12-11 08:56:06'),
(2, 'Liên hệ với chúng tôi', '<shortcode>[contact-form display_fields=\"phone,email,subject,address\" mandatory_fields=\"phone,email\" title=\"Chúng tôi có thể giúp gì cho bạn?\" description=\"Khi bạn cần giải pháp, chúng tôi sẵn sàng lắng nghe và đồng hành để tìm ra hướng đi phù hợp nhất. Dù bạn đang tìm kiếm tư vấn công nghệ, hỗ trợ kỹ thuật, hay muốn tối ưu hóa quy trình làm việc – chúng tôi luôn có mặt để giúp đỡ. Với đội ngũ chuyên môn cao và tinh thần tận tâm, chúng tôi cam kết mang đến cho bạn trải nghiệm hỗ trợ nhanh chóng, hiệu quả và chuyên nghiệp.\" quantity=\"3\" title_1=\"Địa chỉ\" icon_1=\"ti ti-map-pin\" description_1=\"tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam\" title_2=\"Số điện thoại\" icon_2=\"ti ti-phone-call\" description_2=\"+84 973 73 56 79\" title_3=\"E-mail\" icon_3=\"ti ti-mail\" description_3=\"contact@hisotech.com\" form_title=\"Gửi tin nhắn cho chúng tôi\" form_description=\"Địa chỉ email của bạn sẽ được bảo mật. Các trường bắt buộc được gắn dấu*\" form_button_label=\"Gửi\" enable_lazy_loading=\"no\"][/contact-form]</shortcode><shortcode>[google-map height=\"500\"]tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam[/google-map]</shortcode>', 1, 'pngtree-business-technology-digital-high-tech-world-background-backgroundtechnology-backgroundhigh-t.jpg', 'default', 'Khi bạn cần giải pháp, chúng tôi sẵn sàng lắng nghe và đồng hành để tìm ra hướng đi phù hợp nhất. Dù bạn đang tìm kiếm tư vấn công nghệ, hỗ trợ kỹ thuật, hay muốn tối ưu hóa quy trình làm việc – chúng tôi luôn có mặt để giúp đỡ. Với đội ngũ chuyên môn cao và tinh thần tận tâm, chúng tôi cam kết mang đến cho bạn trải nghiệm hỗ trợ nhanh chóng, hiệu quả và chuyên nghiệp.', 'published', '2024-12-09 00:01:18', '2025-06-06 09:54:55'),
