(4, 'Giới thiệu về công ty', '<shortcode>[about-us-information style=\"style-11\" title=\"Chúng tôi cung cấp các giải pháp giúp doanh nghiệp tối ưu hóa và phát triển.\" subtitle=\"KHÁM PHÁ NGAY VỀ\" description=\"Chúng tôi xử lý hiệu quả các nhiệm vụ có mức độ phức tạp khác nhau, cung cấp các cam kết dài hạn và thường xuyên nắm vững các công nghệ mới trong từng lĩnh vực chuyên môn. Danh mục dự án của chúng tôi bao gồm hàng chục dự án.\" image=\"pexels-jonathanborba-14263441.jpg\" image_1=\"pexels-pixabay-38519.jpg\" image_2=\"pexels-pixabay-355952.jpg\" quantity=\"3\" title_1=\"Doanh nghiệp đồng hành\" title_2=\"Phân tích và nghiên cứu\" title_3=\"Nhanh chóng, tiện lợi\" data_count=\"15+\" data_count_description=\"Dự án &lt;br&gt; Đã hoàn thành\" button_label=\"Liên hệ với chúng tôi\" button_url=\"/contact-us\" background_color=\"transparent\" enable_lazy_loading=\"no\"][/about-us-information]</shortcode><p>&nbsp;</p><shortcode>[about-us-information style=\"style-12\" title=\"Digital solutions for your business\" subtitle=\"WHY CHOOSE US\" description=\"We successfully solve tasks of varying levels of complexity, ensuring timely execution and regularly mastering new technological methods.\" quantity=\"4\" title_1=\"Technology solutions\" description_1=\"Providing high-tech solutions for businesses\" icon_1=\"ti ti-chart-histogram\" title_2=\"Software design &amp; development\" description_2=\"Provide software services such as web/app for your operations and business\" icon_2=\"ti ti-building-bank\" title_3=\"Software management support\" description_3=\"We provide personnel who can help you manage the software easily.\" icon_3=\"ti ti-ad-2\" title_4=\"Hardware supply\" description_4=\"Provide hardware devices that integrate with our software, helping you synchronize the administration process\" icon_4=\"ti ti-box-model\" background_color=\"rgb(23, 26, 124)\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[site-statistics style=\"style-1\" quantity=\"4\" title_1=\"Project completed\" data_1=\"45\" unit_1=\"+\" image_1=\"icons/trophy.png\" title_2=\"Our satisfied customers\" data_2=\"92\" unit_2=\"K\" image_2=\"icons/star.png\" title_3=\"We support worldwide\" data_3=\"19\" unit_3=\"+\" image_3=\"icons/popularity.png\" title_4=\"Number of years of corporate governance experience\" data_4=\"25\" unit_4=\"+\" image_4=\"icons/time.png\" background_image=\"backgrounds/site-statistics-bg.png\" background_color=\"rgb(255, 251, 243)\" enable_lazy_loading=\"yes\"][/site-statistics]</shortcode><shortcode>[team style=\"style-4\" title=\"Specialist you can contact\" subtitle=\"MEET OUR TEAM\" team_ids=\"1,2,9,10\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/team]</shortcode>', 1, NULL, 'full-width', 'Chúng tôi xử lý hiệu quả các nhiệm vụ có mức độ phức tạp khác nhau, cung cấp các cam kết dài hạn và thường xuyên nắm vững các công nghệ mới trong từng lĩnh vực chuyên môn. Danh mục dự án của chúng tôi bao gồm hàng chục dự án.', 'published', '2024-12-09 00:01:18', '2025-06-07 08:30:13'),
(5, 'Finance Giới Thiệu', '<shortcode>[about-us-information style=\"style-13\" title=\"Đội ngũ nhiệt tình &lt;br&gt; &lt;span&gt;Luôn&lt;/span&gt; mang lại những giải pháp &lt;span&gt;Tuyệt vời&lt;/span&gt;\" description=\"Hisotech mang đến các giải pháp công nghệ hiện đại, tối ưu cho doanh nghiệp trong kỷ nguyên số. Chúng tôi kết hợp giữa tư duy sáng tạo và kỹ thuật tiên tiến để tạo nên giá trị bền vững. Đội ngũ của Hisotech không ngừng đổi mới, cam kết đồng hành cùng khách hàng trên hành trình chuyển đổi số toàn diện.\" image=\"general/about-us-information-13.jpg\" quantity=\"6\" data_count=\"25\" data_count_description=\"Số năm kinh nghiệm\" background_color=\"transparent\" enable_lazy_loading=\"no\"][/about-us-information]</shortcode><shortcode>[site-statistics style=\"style-1\" quantity=\"4\" title_1=\"Successfully Completed Projects\" data_1=\"45\" unit_1=\"+\" image_1=\"icons/trophy.png\" title_2=\"Satisfied 100% Our Clients\" data_2=\"92\" unit_2=\"K\" image_2=\"icons/star.png\" title_3=\"All Over The World We Are Available\" data_3=\"19\" unit_3=\"+\" image_3=\"icons/popularity.png\" title_4=\"Years of Experiences To Run This Company\" data_4=\"25\" unit_4=\"+\" image_4=\"icons/time.png\" background_image=\"backgrounds/site-statistics-bg.png\" background_color=\"rgb(255, 251, 243)\" enable_lazy_loading=\"yes\"][/site-statistics]</shortcode><shortcode>[contact-block style=\"style-1\" title=\"Mang đến dịch vụ tốt nhất cho doanh nghiệp của bạn\" subtitle=\"Gọi miễn phí\" phone_number=\"+ 84 973 73 56 79\" button_label=\"Yêu cầu cuộc gọi\" button_url=\"tel:0973735679\" background_image=\"backgrounds/contact-block-bg.jpg\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/contact-block]</shortcode><shortcode>[team style=\"style-1\" title=\"Chuyên viên bạn có thể liên hệ\" subtitle=\"GẶP GỠ ĐỘI NHÓM CHÚNG TÔI\" description=\"Quyền tự do lựa chọn của chúng ta là không bị giới hạn, và khi không có gì ngăn cản ta làm điều bạn yêu thích nhất, mọi niềm vu