(18, 'Các bước hoạt động', '<shortcode>[instruction-steps title=\"Hợp Tác Cùng Chúng Tôi Về Dịch Vụ Giải Pháp Công Nghệ Qua Hướng Dẫn Từng Bước Sau\" description=\"Khám phá cách công ty chúng tôi có thể hỗ trợ doanh nghiệp của bạn với các dịch vụ với giải pháp công nghệ toàn diện. Từ cung cấp thiết bị vật lý đến lập trình phần mềm, chúng tôi đều sẵn sàng đồng hành. Liên hệ với chúng tôi ngay hôm nay để bắt đầu!\" quantity=\"3\" title_1=\"Bước 1: Tư vấn ban đầu\" description_1=\"Lên lịch gặp gỡ chuyên viên của chúng tôi để tư vấn cũng như biết thêm về mục đích và nhu cầu của bạn\" icon_1=\"ti ti-chart-pie\" button_label_1=\"Đọc thêm\" button_url_1=\"/contact-us\" title_2=\"Bước 2: Triển khai và demo dự án\" description_2=\"Hẹn lịch gửi bản demo cùng báo giá và gặp gỡ để chỉnh sửa dự án theo yêu cầu của bạn\" icon_2=\"ti ti-bulb\" button_label_2=\"Đọc thêm\" button_url_2=\"/contact-us\" title_3=\"Bước 3: Ký kết hợp đồng và triển khai dự án thực tế\" description_3=\"Sau khi chỉnh sửa bản demo, chúng ta sẽ cùng thống nhất các dịch vụ bạn sử dụng và triển khai theo hợp đồng bàn giao.\" icon_3=\"ti ti-rocket\" button_label_3=\"Đọc thêm\" button_url_3=\"/contact-us\" background_color=\"rgb(20, 23, 108)\"][/instruction-steps]</shortcode><p><br><br>&nbsp;</p>', 1, NULL, 'full-width', '', 'published', '2024-12-09 00:01:18', '2025-04-14 03:19:40'),
