INSERT INTO `pages_translations` (`lang_code`, `pages_id`, `name`, `description`, `content`) VALUES
('en_US', 1, 'Trang chủ', 'Home Hisotech Group, Hisotech, HisotechGroup', '<shortcode>[simple-slider style=\"style-2\" key=\"main-menu-eng\"][/simple-slider]</shortcode><shortcode>[site-statistics style=\"style-1\" quantity=\"4\" title_1=\"Completed projects\" data_1=\"45\" unit_1=\"+\" image_1=\"icons/trophy.png\" title_2=\"100% customer satisfaction\" data_2=\"92\" unit_2=\"K\" image_2=\"icons/star.png\" title_3=\"We are always ready to support worldwide\" data_3=\"19\" unit_3=\"+\" image_3=\"icons/popularity.png\" title_4=\"Number of years running the company\" data_4=\"25\" unit_4=\"+\" image_4=\"icons/time.png\" background_image=\"backgrounds/site-statistics-bg.png\" background_color=\"#FFFBF3\" enable_lazy_loading=\"yes\"][/site-statistics]</shortcode><shortcode>[services style=\"style-5\" title=\"Best Products &lt;br&gt; For Your Business\" subtitle=\"WHAT WE OFFER\" service_ids=\"1,2,3,4,5,6\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/services]</shortcode><shortcode>[include-webdemo][/include-webdemo]</shortcode><shortcode>[testimonials style=\"style-2\" title=\"What our customers say\" subtitle=\"CUSTOMER TESTIMONIALS\" testimonial_ids=\"1,2,3,4\" background_color=\"rgb(207, 226, 243)\" enable_lazy_loading=\"yes\"][/testimonials]</shortcode><shortcode>[about-us-information style=\"style-6\" title=\"We provide comprehensive technology solutions for your business\" subtitle=\"ABOUT OUR COMPANY\" description=\"Hisotech provides modern, optimal technology solutions for businesses in the digital age. We combine creative thinking and advanced technology to create sustainable value. Hisotech\'s team is constantly innovating, committed to accompanying customers on the journey of comprehensive digital transformation..\" image=\"014bbcf8b05aef017c85102b68dbd37e.jpg\" image_1=\"1179ca0d343a36376df117e5056144ab-1.jpg\" image_2=\"dd8d2bb106af8281dc33d9066ac2b53d-1.jpg\" quantity=\"2\" title_1=\"Support Group\" description_1=\"We support your requests 24/7\" icon_1=\"ti ti-24-hours\" title_2=\"Expert\" description_2=\"Meet and talk to experts about your problem\" icon_2=\"ti ti-report-money\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[contact-block style=\"style-3\" title=\"We provide specialized technology solutions, suitable for all businesses\" subtitle=\"Improve your business by contacting us now\" button_label=\"See all services\" button_url=\"/services\" background_image=\"backgrounds/contact-block-bg-3.png\" background_color=\"rgb(20, 23, 108)\" enable_lazy_loading=\"no\"][/contact-block]</shortcode><shortcode>[team style=\"style-5\" title=\"Meet our team\" subtitle=\"Technical experts\" team_ids=\"1,2,3,4\" button_label=\"Contact us\" button_url=\"/contact-us\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/team]</shortcode><shortcode>[faqs title=\"Frequently Asked Questions\" description=\"Our freedom of choice is limitless, and when nothing stops us from doing what we love most, all joy becomes within reach.\" image=\"7c3e8109104a75c1f23384a8aaa37837.jpg\" faq_category_ids=\"1,2,3\" limit=\"3\" floating_block_icon=\"ti ti-24-hours\" floating_block_title=\"Need help?\" floating_block_description=\"Feeling curious? Read through some of our FAQs or contact our Support team for help.\" enable_lazy_loading=\"yes\"][/faqs]</shortcode><shortcode>[about-us-information style=\"style-14\" title=\"You want to talk to an expert\" description=\"We effectively handle tasks of varying complexity, provide long-term commitments and continuously improve our expertise.\" image=\"8d0c4f7a3b8d936f6a83385e47e72e2a.jpg\" quantity=\"3\" title_1=\"Accompanying businesses\" title_2=\"Analysis and research\" title_3=\"Fast, convenient\" button_label=\"See more\" button_url=\"/contact-us\" background_color=\"rgb(236, 246, 250)\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[blog-posts style=\"style-1\" category_ids=\"2,3,4,5\" title=\"Featured news and information\" subtitle=\"NEW UPDATED ARTICLES\" limit=\"3\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/blog-posts]</shortcode>'),
('en_US', 2, 'Contact us', 'When you need a solution, we are here to listen and work with you to find the right path. Whether you are looking for technology consulting, technical support, or want to optimize your workflow – we are here to help. With a team of highly skilled and dedicated professionals, we are committed to providing you with a fast, efficient, and professional support experience.', '<shortcode>[contact-form display_fields=\"phone,email,subject,address\" mandatory_fields=\"phone,email\" title=\"How can we help you?\" description=\"When you need a solution, we are ready to listen and accompany you to find the most suitable direction. Whether you are looking for technology consulting, technical support, or want to optimize your workflow - we are always here to help. With a team of highly skilled and dedicated staff, we are committed to providing you with a fast, efficient and professional support experience.\" quantity=\"3\" title_1=\"Address\" icon_1=\"ti ti-map-pin\" description_1=\"building C2, D\'Capital, Tran Duy Hung street, Trung Hoa ward, Cau Giay district, Hanoi, Vietnam\" title_2=\"Phone number\" icon_2=\"ti ti-phone-call\" description_2=\"+84 973 73 56 79\" title_3=\"E-mail\" icon_3=\"ti ti-mail\" description_3=\"contact@hisotech.com\" form_title=\"Send us a message\" form_description=\"Your email address will be kept confidential. Required fields are marked with an asterisk*\" form_button_label=\"Send\" enable_lazy_loading=\"no\"][/contact-form]</shortcode><shortcode>[google-map height=\"500\"]Building C2, D\'Capital, Tran Duy Hung Street, Trung Hoa Ward, Cau Giay District, Hanoi, Vietnam[/google-map]</shortcode>'),
('en_US', 4, 'About the company', 'We effectively handle tasks of varying complexity, provide long-term commitments, and regularly master new technologies in each area of expertise. Our project portfolio includes dozens of projects.', '<shortcode>[about-us-information style=\"style-11\" title=\"We provide solutions that help businesses optimize and grow.\" subtitle=\"DISCOVER NOW\" description=\"We effectively handle tasks of varying complexity, provide long-term commitments, and regularly master new technologies in each area of ​​expertise. Our project portfolio includes dozens of projects.\" image=\"pexels-jonathanborba-14263441.jpg\" image_1=\"pexels-pixabay-38519.jpg\" image_2=\"pexels-pixabay-355952.jpg\" quantity=\"3\" title_1=\"Companion Enterprises\" title_2=\"Analysis and Research\" title_3=\"Fast, Convenient\" data_count=\"15+\" data_count_description=\"Projects &lt;br&gt; Completed\" button_label=\"Contact Us\" button_url=\"/contact-us\" background_color=\"transparent\" enable_lazy_loading=\"no\"][/about-us-information]</shortcode><p>&nbsp;</p><shortcode>[about-us-information style=\"style-12\" title=\"Digital solutions for your business\" subtitle=\"WHY CHOOSE US\" description=\"We successfully solve tasks of varying levels of complexity, ensuring timely execution and regularly mastering new technological methods.\" quantity=\"4\" title_1=\"Technology solutions\" description_1=\"Providing high-tech solutions for businesses\" icon_1=\"ti ti-chart-histogram\" title_2=\"Software design &amp; development\" description_2=\"Provide software services such as web/app for your operations and business\" icon_2=\"ti ti-building-bank\" title_3=\"Software management support\" description_3=\"We provide personnel who can help you manage the software easily.\" icon_3=\"ti ti-ad-2\" title_4=\"Hardware supply\" description_4=\"Provide hardware devices that integrate with our software, helping you synchronize the administration process\" icon_4=\"ti ti-box-model\" background_color=\"rgb(23, 26, 124)\" enable_lazy_loading=\"yes\"][/about-us-information]</shortcode><shortcode>[site-statistics style=\"style-1\" quantity=\"4\" title_1=\"Project completed\" data_1=\"45\" unit_1=\"+\" image_1=\"icons/trophy.png\" title_2=\"Our satisfied customers\" data_2=\"92\" unit_2=\"K\" image_2=\"icons/star.png\" title_3=\"We support worldwide\" data_3=\"19\" unit_3=\"+\" image_3=\"icons/popularity.png\" title_4=\"Number of years of corporate governance experience\" data_4=\"25\" unit_4=\"+\" image_4=\"icons/time.png\" background_image=\"backgrounds/site-statistics-bg.png\" background_color=\"rgb(255, 251, 243)\" enable_lazy_loading=\"yes\"][/site-statistics]</shortcode><shortcode>[team style=\"style-4\" title=\"Specialist you can contact\" subtitle=\"MEET OUR TEAM\" team_ids=\"1,2,9,10\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/team]</shortcode>'),
