('en_US', 18, 'The steps of operation', NULL, '<shortcode>[instruction-steps title=\"Cooperate with us about technology solution services through step by step instructions\" description=\"Discover how our company can support your business with services with comprehensive technology solutions. From providing physical equipment to software programming, we are all ready to accompany. Contact us today to start!\" quantity=\"3\" title_1=\"Bước 1: Tư vấn ban đầu\" description_1=\"Lên lịch gặp gỡ chuyên viên của chúng tôi để tư vấn cũng như biết thêm về mục đích và nhu cầu của bạn\" icon_1=\"ti ti-chart-pie\" button_label_1=\"Đọc thêm\" button_url_1=\"/contact-us\" title_2=\"Bước 2: Triển khai và demo dự án\" description_2=\"Hẹn lịch gửi bản demo cùng báo giá và gặp gỡ để chỉnh sửa dự án theo yêu cầu của bạn\" icon_2=\"ti ti-bulb\" button_label_2=\"Đọc thêm\" button_url_2=\"/contact-us\" title_3=\"Bước 3: Ký kết hợp đồng và triển khai dự án thực tế\" description_3=\"Sau khi chỉnh sửa bản demo, chúng ta sẽ cùng thống nhất các dịch vụ bạn sử dụng và triển khai theo hợp đồng bàn giao.\" icon_3=\"ti ti-rocket\" button_label_3=\"Đọc thêm\" button_url_3=\"/contact-us\" background_color=\"rgb(20, 23, 108)\"][/instruction-steps]</shortcode><p><br><br>&nbsp;</p>'),
('en_US', 19, 'Pricing', NULL, '<shortcode>[pricing title=\"Our good prices for you\" subtitle=\"Flexible price list\" package_ids=\"1,2,3\" number_of_items_per_row=\"3\" background_image=\"backgrounds/blog-posts-bg.jpg\" background_color=\"transparent\" enable_lazy_loading=\"yes\"][/pricing]</shortcode>'),
