(1, 'Gói cơ bản', 'Các tính năng nâng cao cho các chuyên gia cần tùy chỉnh nhiều hơn.', '<p>Đây là nội dung gói</p>', '25,000,000đ', '30,000,000đ', 'monthly', '+ 100 hoạt động của người dùng\r\n+ Hạn chế truy cập\r\n+ Không có phí ẩn\r\n+ 01 Cập nhật thời gian\r\n+ Tệp nguồn figma\r\n+ Nhiều cơ sở khác', 'published', 0, 'Mua gói ngay', '/contact-us', '2024-12-09 00:01:26', '2025-04-14 10:20:44'),
(2, 'Team Plan', 'All the basics for businesses that are just getting started.', '<p>This is package content</p>\n', '$49', '$499', 'monthly', '+ 1000 User Activities\n+ Unlimited Access\n+ No Hidden Charge\n+ 03 Time Updates\n+ Figma Source File\n+ Many More Facilities', 'published', 1, 'Get The Plan Now', '/contact-us', '2024-12-09 00:01:26', '2024-12-09 00:01:26'),
