(1, 1, 'Thiết kế giao diện website doanh nghiệp', 'Giao diện website chuyên nghiệp, tối ưu trải nghiệm người dùng.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Phân tích yêu cầu và nhận diện thương hiệu.\" icon_1=\"ti ti-plant-2\" title_2=\"Thiết kế UI/UX theo chuẩn hiện đại.\" icon_2=\"ti ti-brand-adobe-indesign\" title_3=\"Tối ưu tốc độ tải trang và khả năng SEO.\" icon_3=\"ti ti-brand-speedtest\" title_4=\"Dễ sử dụng\" icon_4=\"ti ti-adjustments-pause\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Giúp doanh nghiệp của bạn tết kiệm chi phí\" description=\"Tăng tốc độ tăng trưởng kinh doanh của bạn thông qua các dịch vụ toàn diện của chúng tôi phù hợp để đáp ứng nhu cầu của bạn.\" image=\"pexels-tranmautritam-226172.jpg\" quantity=\"3\" title_1=\"Thiết kế theo yêu cầu\" title_2=\"Phân tích và đặc tả chức năng\" title_3=\"Nhanh chóng &amp; dễ dùng\"][/content-featured]</shortcode><p>&nbsp;</p>', 0, 'pexels-pixabay-38519.jpg', '[\"news\\/1.jpg\"]', 1822, 'published', '2024-12-09 00:01:26', '2025-06-03 14:28:11'),
(2, 1, 'Thiết kế ứng dụng di động đa nền tảng (iOS/Android)', 'Ứng dụng mượt mà, thân thiện với người dùng trên mọi thiết bị.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"pexels-jonathanborba-14263441.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>&nbsp;</p>', 0, 'pexels-jonathanborba-14263441.jpg', '[\"news\\/3.jpg\"]', 8318, 'published', '2024-12-09 00:01:26', '2025-06-03 14:29:11'),
(3, 1, 'Thiết kế website thương mại điện tử', 'Website bán hàng đầy đủ tính năng, hỗ trợ thanh toán online.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"pexels-tranmautritam-226172.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>&nbsp;</p>', 1, 'pexels-tranmautritam-226172.jpg', '[\"news\\/2.jpg\"]', 6662, 'published', '2024-12-09 00:01:26', '2025-06-03 14:29:48'),
(4, 2, 'Tích hợp hệ thống IoT cho doanh nghiệp', 'Kết nối và điều khiển thiết bị qua Internet.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"pexels-pixabay-38519.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>&nbsp;</p>', 0, 'pexels-jakubzerdzicki-30170004.jpg', '[\"news\\/4.jpg\"]', 3738, 'published', '2024-12-09 00:01:26', '2025-06-03 14:30:28'),
(5, 2, 'Kết nối phần mềm quản lý với thiết bị bán hàng (POS)', 'Đồng bộ hóa hệ thống quản lý với máy POS, máy in hóa đơn.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"unnamed.png\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>&nbsp;</p>', 1, 'unnamed.png', '[\"news\\/3.jpg\"]', 2444, 'published', '2024-12-09 00:01:27', '2025-06-03 14:31:12'),
(6, 2, 'Giải pháp kết nối thiết bị công nghiệp (PLC, cảm biến, SCADA)', 'Kết nối và điều khiển thiết bị trong nhà máy, xưởng sản xuất.', '<h2><strong>Giải pháp của chúng tôi gồm những gì?</strong></h2><h3>🔧 <strong>Kết nối phần cứng</strong></h3><ul><li>Hỗ trợ hầu hết các dòng <strong>PLC phổ biến</strong>: Siemens, Mitsubishi, Omron, Delta, Schneider, Rockwell, v.v.</li><li>Kết nối <strong>cảm biến analog/digital</strong>, thiết bị đo lường, bộ truyền tín hiệu...</li><li>Thiết lập hệ thống <strong>gateway IoT công nghiệp</strong> (IIoT Gateway) với chuẩn giao tiếp Modbus, OPC UA, MQTT, v.v.</li></ul><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Design \" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>Trong bối cảnh chuyển đổi số ngày càng mạnh mẽ trong lĩnh vực công nghiệp, việc kết nối và quản lý hiệu quả các thiết bị như PLC, cảm biến, SCADA đang trở thành yếu tố cốt lõi giúp doanh nghiệp nâng cao năng lực cạnh tranh. Chúng tôi mang đến <strong>giải pháp kết nối thiết bị công nghiệp toàn diện</strong>, giúp bạn dễ dàng thu thập, giám sát và phân tích dữ liệu từ hệ thống sản xuất.</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"scada-ecosystem-with-ignition.png\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>Tối ưu hóa vận hành – Nâng cao năng suất – Chuẩn hóa dữ liệu sản xuất</p>', 0, 'scada-ecosystem-with-ignition.png', '[\"news\\/2.jpg\"]', 1223, 'published', '2024-12-09 00:01:27', '2025-04-15 02:26:33'),
(7, 3, 'Khảo sát người dùng mục tiêu', 'Tìm hiểu nhu cầu, thói quen và phản hồi của khách hàng tiềm năng.', '<p><strong>Để đảm bảo giải pháp đáp ứng đúng nhu cầu thực tế của doanh nghiệp Việt</strong>, chúng tôi rất mong nhận được phản hồi từ bạn qua <strong>bảng khảo sát ngắn (chỉ mất 3–5 phút)</strong>.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Doanh nghiệp của bạn hoạt động trong lĩnh vực nào?\" icon_1=\"ti ti-plant-2\" title_2=\"Doanh nghiệp đang sử dụng các thiết bị/sản phẩm sau đây?\" icon_2=\"ti ti-assembly\" title_3=\"Những vấn đề doanh nghiệp bạn đang gặp phải trong quá trình vận hành?\" icon_3=\"ti ti-lock-cog\" title_4=\"Mức độ ưu tiên của việc kết nối và số hóa thiết bị trong 12 tháng tới?\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><h2 class=\"\" data-start=\"1167\" data-end=\"1216\">🧩 <strong data-start=\"1173\" data-end=\"1216\">Bạn nhận được gì khi tham gia khảo sát?</strong></h2><ul data-start=\"1217\" data-end=\"1425\"><li class=\"\" data-start=\"1217\" data-end=\"1285\"><p class=\"\" data-start=\"1219\" data-end=\"1285\">✅ Được <strong data-start=\"1226\" data-end=\"1253\">ưu tiên tư vấn miễn phí</strong> về giải pháp kết nối thiết bị</p></li><li class=\"\" data-start=\"1286\" data-end=\"1352\"><p class=\"\" data-start=\"1288\" data-end=\"1352\">✅ Nhận <strong data-start=\"1295\" data-end=\"1317\">bản demo giải pháp</strong> phù hợp với mô hình doanh nghiệp</p></li><li class=\"\" data-start=\"1353\" data-end=\"1425\"><p class=\"\" data-start=\"1355\" data-end=\"1425\">✅ Cơ hội tham gia chương trình <strong data-start=\"1386\" data-end=\"1425\">dùng thử hoặc ưu đãi triển khai sớm</strong></p></li></ul><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"khao-sat-nhu-cau-khach-hang.png\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p><strong>Chúng tôi tin rằng, giải pháp tốt nhất luôn bắt đầu từ việc lắng nghe khách hàng.</strong><br>Xin chân thành cảm ơn bạn đã đồng hành cùng chúng tôi trên hành trình số hóa ngành công nghiệp!</p>', 0, 'khao-sat-nhu-cau-khach-hang.png', '[\"news\\/4.jpg\"]', 925, 'published', '2024-12-09 00:01:27', '2025-04-15 02:34:20'),
(8, 3, 'Phân tích đối thủ cạnh tranh', 'Nắm bắt chiến lược và hoạt động của đối thủ trên thị trường.', '<p>Trong bối cảnh công nghiệp 4.0 bùng nổ, hàng loạt doanh nghiệp cung cấp <strong>giải pháp kết nối thiết bị công nghiệp</strong> đang tham gia vào cuộc đua số hóa sản xuất. Việc hiểu rõ đối thủ cạnh tranh không chỉ giúp chúng ta nhận diện thị trường, mà còn là cơ sở để <strong>xác định điểm khác biệt và xây dựng chiến lược cạnh tranh hiệu quả</strong>.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Nhóm đối thủ chính trên thị trường\" icon_1=\"ti ti-plant-2\" title_2=\"Các yếu tố cạnh tranh chính\" icon_2=\"ti ti-assembly\" title_3=\"Cơ hội và chiến lược tạo khác biệt\" icon_3=\"ti ti-lock-cog\" title_4=\"Ngành Giải Pháp Kết Nối Thiết Bị Công Nghiệp\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><div class=\"gtx-body\" style=\"color:rgb(37,37,37);font-family:Roboto, arial, sans-serif;font-size:18px;font-style:normal;font-weight:400;margin:5px auto;padding:5px 0px;word-spacing:0px;\">Mặc dù chúng tôi cung cấp sự tiện lợi trọn gói của nhiều dịch vụ pháp lý, tài chính tích hợp dưới một mái nhà, nhưng đôi khi khách hàng của chúng tôi cần lời khuyên chuyên môn vượt quá phạm vi chuyên môn của chúng tôi. Đó là lý do tại sao chúng tôi đã phát triển mối quan hệ làm việc chặt chẽ với một số đối tác chiến lược.</div><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"nhung-loi-ich-viec-phan-tich-doi-thu-canh-tranh-mang-lai.png\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Finana trân trọng sự tin tưởng của bạn. Khách hàng của chúng tôi chọn Dentace Ducts vì biết rằng chúng tôi thực sự là khu vực tốt nhất.</span></span></p>', 1, 'nhung-loi-ich-viec-phan-tich-doi-thu-canh-tranh-mang-lai.png', '[\"news\\/4.jpg\"]', 1263, 'published', '2024-12-09 00:01:27', '2025-04-15 02:41:00'),
(9, 3, 'Dự báo xu hướng thị trường', 'Đưa ra các dự đoán thị trường ngắn hạn và dài hạn.', '<p>when an unknown printer took a galley of type and scrambled it to make a type specimen bookhas survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchan galley of type and scrambled it to make a type specimen book.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>Although we offer the one-stop convenience of annery integrated range of legal, financial services under one roof, there are occasions when our clients areaneed specia- list advice beyond the scope of our own expertise. That’s why we’ve developed close working relationships with a number of strategic partner.</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"general/content-featured.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>Finanappreciate your trust greatly Our clients choose dentace ducts because kn ow we are the best area Awaitingare really.</p>', 1, 'pexels-serpstat-177219-572056.jpg', '[\"news\\/4.jpg\"]', 4908, 'published', '2024-12-09 00:01:27', '2025-04-15 03:08:49'),
(10, 4, 'Tư vấn và triển khai chuyển đổi số', 'Giúp doanh nghiệp tối ưu quy trình vận hành bằng công nghệ.', '<p>when an unknown printer took a galley of type and scrambled it to make a type specimen bookhas survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchan galley of type and scrambled it to make a type specimen book.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>Although we offer the one-stop convenience of annery integrated range of legal, financial services under one roof, there are occasions when our clients areaneed specia- list advice beyond the scope of our own expertise. That’s why we’ve developed close working relationships with a number of strategic partner.</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"general/content-featured.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>Finanappreciate your trust greatly Our clients choose dentace ducts because kn ow we are the best area Awaitingare really.</p>', 1, '7c3e8109104a75c1f23384a8aaa37837.jpg', '[\"news\\/4.jpg\"]', 450, 'published', '2024-12-09 00:01:27', '2025-04-15 03:09:10'),
(11, 4, 'Xây dựng hệ thống quản lý nội bộ (Intranet)', 'Hệ thống quản lý công việc, nhân sự, tài liệu cho doanh nghiệp.', '<p>when an unknown printer took a galley of type and scrambled it to make a type specimen bookhas survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchan galley of type and scrambled it to make a type specimen book.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>Although we offer the one-stop convenience of annery integrated range of legal, financial services under one roof, there are occasions when our clients areaneed specia- list advice beyond the scope of our own expertise. That’s why we’ve developed close working relationships with a number of strategic partner.</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"general/content-featured.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>Finanappreciate your trust greatly Our clients choose dentace ducts because kn ow we are the best area Awaitingare really.</p>', 1, '1179ca0d343a36376df117e5056144ab-1.jpg', '[\"news\\/4.jpg\"]', 7809, 'published', '2024-12-09 00:01:27', '2025-04-15 03:10:53'),
(12, 4, 'Phát triển giải pháp AI tùy biến', 'Ứng dụng AI vào quy trình xử lý dữ liệu, chăm sóc khách hàng,...', '<p>when an unknown printer took a galley of type and scrambled it to make a type specimen bookhas survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchan galley of type and scrambled it to make a type specimen book.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Thiết kế UI cho mobile theo chuẩn Material Design và Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"Kết nối API, cơ sở dữ liệu.\" icon_2=\"ti ti-assembly\" title_3=\"Đảm bảo hiệu suất và bảo mật.\" icon_3=\"ti ti-lock-cog\" title_4=\"Giao diện dễ dùng\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>Although we offer the one-stop convenience of annery integrated range of legal, financial services under one roof, there are occasions when our clients areaneed specia- list advice beyond the scope of our own expertise. That’s why we’ve developed close working relationships with a number of strategic partner.</p><shortcode>[content-featured title=\"Tăng vốn nhanh hơn và đàm phán theo các điều khoản của riêng bạn\" description=\"Đẩy nhanh sự phát triển doanh nghiệp của bạn thông qua các dịch vụ toàn diện của chúng tôi được thiết kế riêng để đáp ứng nhu cầu của bạn.\" image=\"general/content-featured.jpg\" quantity=\"3\" title_1=\"Đúng thứ bạn cần\" title_2=\"Phân tích &amp; Nghiên cứu chính xác\" title_3=\"Nhanh chóng &amp; tiện lợi\"][/content-featured]</shortcode><p>Finanappreciate your trust greatly Our clients choose dentace ducts because kn ow we are the best area Awaitingare really.</p>', 0, 'pexels-jakubzerdzicki-30170004.jpg', '[\"news\\/4.jpg\"]', 8021, 'published', '2024-12-09 00:01:27', '2025-04-15 03:11:05');
INSERT INTO `pf_services_translations` (`lang_code`, `pf_services_id`, `name`, `description`, `content`) VALUES
('en_US', 1, 'Business website interface design', 'Professional website interface, optimized user experience.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Requirements analysis and brand identity.\" icon_1=\"ti ti-plant-2\" title_2=\"UI/UX design according to modern standards.\" icon_2=\"ti ti-brand-adobe-indesign\" title_3=\"Optimize page load speed and SEO capabilities.\" icon_3=\"ti ti-brand-speedtest\" title_4=\"Easy to use\" icon_4=\"ti ti-adjustments-pause\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Help your business save costs\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"pexels-tranmautritam-226172.jpg\" quantity=\"3\" title_1=\"Design on request\" title_2=\"Functional analysis and specification\" title_3=\"Fast &amp; easy to use\"][/content-featured]</shortcode><p>&nbsp;</p>'),
('en_US', 2, 'Cross-platform mobile application design (iOS/Android)', 'Smooth, user-friendly application on all devices.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Design UI for mobile according to Material Design and Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"API, database connection.\" icon_2=\"ti ti-assembly\" title_3=\"Ensuring performance and security.\" icon_3=\"ti ti-lock-cog\" title_4=\"Easy-to-use interface\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"pexels-jonathanborba-14263441.jpg\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p>&nbsp;</p>'),
('en_US', 3, 'E-commerce website design', 'Full featured sales website, supports online payment.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Design UI for mobile according to Material Design and Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"API, database connection.\" icon_2=\"ti ti-assembly\" title_3=\"Ensuring performance and security.\" icon_3=\"ti ti-lock-cog\" title_4=\"Easy-to-use interface\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"pexels-tranmautritam-226172.jpg\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p>&nbsp;</p>'),
('en_US', 4, 'Integrating IoT systems for businesses', 'Connect and control devices over the Internet.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Design UI for mobile according to Material Design and Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"API, database connection.\" icon_2=\"ti ti-assembly\" title_3=\"Ensuring performance and security.\" icon_3=\"ti ti-lock-cog\" title_4=\"Easy-to-use interface\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"pexels-pixabay-38519.jpg\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p>&nbsp;</p>'),
('en_US', 5, 'Connect management software to point of sale (POS) devices', 'Synchronize management system with POS machine, receipt printer.', '<p>&nbsp;</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Design UI for mobile according to Material Design and Human Interface Guidelines.\" icon_1=\"ti ti-plant-2\" title_2=\"API, database connection.\" icon_2=\"ti ti-assembly\" title_3=\"Ensuring performance and security.\" icon_3=\"ti ti-lock-cog\" title_4=\"Easy-to-use interface\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>&nbsp;</p><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"unnamed.png\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p>&nbsp;</p>'),
('en_US', 6, 'Industrial equipment connection solution (PLC, sensor, SCADA)', 'Connect and control equipment in factories and production plants.', '<p><strong>What does our solution include?</strong></p><p>🔧 Hardware connection</p><ul><li>Support most popular PLC lines: Siemens, Mitsubishi, Omron, Delta, Schneider, Rockwell, etc.</li><li>Connect analog/digital sensors, measuring devices, signal transmitters...</li><li>Set up an industrial IoT gateway system (IIoT Gateway) with communication standards Modbus, OPC UA, MQTT, etc.</li></ul><shortcode>[content-feature-list quantity=\"4\" title_1=\"Design UI for mobile according to Design standards\" icon_1=\"ti ti-plant-2\" title_2=\"API, database connection.\" icon_2=\"ti ti-assembly\" title_3=\"Ensuring performance and security.\" icon_3=\"ti ti-lock-cog\" title_4=\"Easy-to-use interface\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><p>In the context of increasingly strong digital transformation in the industrial sector, connecting and effectively managing devices such as PLC, sensors, SCADA is becoming a core factor to help businesses improve their competitiveness. We provide comprehensive industrial device connectivity solutions, helping you easily collect, monitor and analyze data from production systems.</p><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"scada-ecosystem-with-ignition.png\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p>Optimize operations – Improve productivity – Standardize production data</p>'),
('en_US', 7, 'Target User Survey', 'Learn about your potential customers\' needs, habits, and feedback.', '<p><strong>To ensure that the solution meets the actual needs of Vietnamese businesses, we look forward to receiving your feedback via a short survey (it only takes 3-5 minutes).</strong></p><shortcode>[content-feature-list quantity=\"4\" title_1=\"What industry does your business operate in?\" icon_1=\"ti ti-plant-2\" title_2=\"Is your business using the following equipment/products?\" icon_2=\"ti ti-assembly\" title_3=\"What problems are you facing in your business operations?\" icon_3=\"ti ti-lock-cog\" title_4=\"What is the priority of device connectivity and digitization in the next 12 months?\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><h2>🧩 <strong>What do you get for taking the survey?</strong></h2><ul><li>✅ Get priority free consultation on device connection solutions</li><li>✅ Get a demo of a solution that fits your business model</li><li>✅ Opportunity to participate in a trial program or early deployment incentives</li></ul><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"khao-sat-nhu-cau-khach-hang.png\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p><strong>We believe that the best solutions always start with listening to our customers.&nbsp;</strong></p><p>Thank you for joining us on our journey to digitize the industry!</p>'),
('en_US', 8, 'Competitor Analysis', 'Grasp the strategy and activities of competitors in the market.', '<p>In the context of the booming Industry 4.0, a series of businesses providing solutions to connect industrial equipment are participating in the race to digitize production. Understanding competitors not only helps us identify the market, but also is the basis for determining differences and building effective competitive strategies.</p><shortcode>[content-feature-list quantity=\"4\" title_1=\"Main competitors in the market\" icon_1=\"ti ti-plant-2\" title_2=\"Key competitive factors\" icon_2=\"ti ti-assembly\" title_3=\"Opportunities and strategies for differentiation\" icon_3=\"ti ti-lock-cog\" title_4=\"Industrial Equipment Connection Solutions Industry\" icon_4=\"ti ti-ux-circle\"][/content-feature-list]</shortcode><div class=\"gtx-body\" style=\"color:rgb(37,37,37);font-family:Roboto, arial, sans-serif;font-size:18px;font-style:normal;font-weight:400;margin:5px auto;padding:5px 0px;word-spacing:0px;\">While we offer the convenience of a comprehensive range of legal and financial services under one roof, our clients sometimes need specialist advice that goes beyond our scope of expertise. That is why we have developed close working relationships with a number of strategic partners.</div><shortcode>[content-featured title=\"Raise capital faster and negotiate on your own terms\" description=\"Accelerate your business growth through our comprehensive services tailored to meet your needs.\" image=\"nhung-loi-ich-viec-phan-tich-doi-thu-canh-tranh-mang-lai.png\" quantity=\"3\" title_1=\"Just what you need\" title_2=\"Accurate Analysis &amp; Research\" title_3=\"Fast &amp; convenient\"][/content-featured]</shortcode><p><span style=\"color:rgb(37,37,37);font-size:18px;\"><span style=\"font-family:Roboto, arial, sans-serif;font-style:normal;font-weight:400;word-spacing:0px;\">Finana values ​​your trust. Our customers choose Dentace Ducts knowing that we are truly the best in the area.</span></span></p>'),
