(23, 'Botble\\Page\\Models\\Page', 20, 1, 'description', NULL, '', '2025-04-14 03:24:30', '2025-04-14 03:24:30'),
(24, 'Botble\\Blog\\Models\\Post', 3, 1, 'name', 'From Brainstorm to Boardroom: Crafting a Winning Business Plan', 'HISOTECH: Khai Phá Tương Lai – Câu Chuyện Startup Của Sự Đổi Mới', '2025-04-14 03:29:33', '2025-04-14 03:29:33'),
(25, 'Botble\\Blog\\Models\\Post', 3, 1, 'description', 'Unleash your inner strategist. This post outlines the key elements of a compelling business plan.', 'Tại HISOTECH, chúng tôi là một startup với sứ mệnh táo bạo nhằm định hình lại ngành công nghệ. Kể từ khi thành lập vào năm 2020, chúng tôi đã không ngừng đổi mới, truyền cảm hứng, và trao quyền cho các doanh nghiệp bằng những giải pháp công nghệ mang tính đột phá.', '2025-04-14 03:29:33', '2025-04-14 03:29:33'),
(26, 'Botble\\Blog\\Models\\Post', 3, 1, 'image', 'news/3.jpg', 'news/21546-1.jpg', '2025-04-14 03:31:17', '2025-04-14 03:31:17'),
(27, 'Botble\\Blog\\Models\\Post', 4, 1, 'name', 'The Art of Delegation: Empowering Your Team for Success', 'Lãnh Đạo Xuất Sắc Tại HISOTECH: Truyền Cảm Hứng Cho Sự Phát Triển và Đổi Mới', '2025-04-14 03:37:40', '2025-04-14 03:37:40'),
(28, 'Botble\\Blog\\Models\\Post', 4, 1, 'description', 'Effective leaders empower others. Learn how to delegate tasks effectively and unlock your team\'s full potential.', 'Tại HISOTECH, chúng tôi tin rằng lãnh đạo xuất sắc là nền tảng của thành công. Là một startup công nghệ được thành lập vào năm 2020, triết lý lãnh đạo của chúng tôi đã đóng vai trò quan trọng trong việc thúc đẩy đổi mới, nuôi dưỡng sự phát triển, và xây dựng một văn hóa xuất sắc. Dưới đây là cách mà phong cách lãnh đạo của chúng tôi tạo nên sự khác biệt và trao quyền cho cả đội ngũ lẫn khách hàng.', '2025-04-14 03:37:40', '2025-04-14 03:37:40'),
(29, 'Botble\\Blog\\Models\\Post', 4, 1, 'image', 'news/4.jpg', 'news/1768-1.jpg', '2025-04-14 03:37:40', '2025-04-14 03:37:40'),
(30, 'Botble\\Blog\\Models\\Post', 5, 1, 'name', 'Customer Centricity: Putting Your Customers at the Heart of Your Business', 'HISOTECH: Chuyển Đổi Doanh Nghiệp Bằng Công Nghệ và Mạng Lưới', '2025-04-14 03:45:30', '2025-04-14 03:45:30'),
(31, 'Botble\\Blog\\Models\\Post', 5, 1, 'description', 'In today\'s competitive market, customer satisfaction is paramount. Discover strategies to prioritize your customers.', 'Tại HISOTECH, chúng tôi là một startup công nghệ với sứ mệnh trao quyền cho doanh nghiệp thông qua các giải pháp sáng tạo và mạng lưới vững chắc. Kể từ khi thành lập vào năm 2020, chúng tôi đã luôn dẫn đầu trong tiến bộ công nghệ, giúp các công ty phát triển mạnh mẽ trong kỷ nguyên số với các công cụ tiên tiến và khả năng kết nối toàn cầu.', '2025-04-14 03:45:30', '2025-04-14 03:45:30'),
(32, 'Botble\\Blog\\Models\\Post', 5, 1, 'image', 'news/5.jpg', 'news/98438-1.jpg', '2025-04-14 03:45:30', '2025-04-14 03:45:30'),
(33, 'Botble\\Blog\\Models\\Post', 6, 1, 'name', 'Data-Driven Decisions: Leveraging Insights to Fuel Business Growth', 'HISOTECH: Xây Dựng Thành Công Bằng Chiến Lược Nhân Sự Xuất Sắc', '2025-04-14 03:50:19', '2025-04-14 03:50:19'),
(34, 'Botble\\Blog\\Models\\Post', 6, 1, 'description', 'Data is king. Learn how to harness the power of data analytics to make informed decisions for your business.', 'Tại HISOTECH, chúng tôi hiểu rằng con người là tài sản quý giá nhất. Là một startup công nghệ được thành lập vào năm 2020, chúng tôi đã xây dựng một chiến lược nhân sự tập trung vào việc thu hút, phát triển, và trao quyền cho nhân tài để thúc đẩy đổi mới và tăng trưởng. Sự cam kết với đội ngũ giúp chúng tôi mang đến kết quả vượt trội cho khách hàng, đồng thời xây dựng một văn hóa làm việc phát tri', '2025-04-14 03:50:19', '2025-04-14 03:50:19'),
(35, 'Botble\\Blog\\Models\\Post', 6, 1, 'image', 'news/6.jpg', 'news/1729-1.jpg', '2025-04-14 03:50:19', '2025-04-14 03:50:19'),
(36, 'Botble\\Blog\\Models\\Post', 7, 1, 'name', 'Building a Strong Brand Identity: Standing Out from the Crowd', 'HISOTECH: Dịch Vụ Khách Hàng Xuất Sắc Cho Trải Nghiệm Mượt Mà', '2025-04-14 03:58:28', '2025-04-14 03:58:28'),
(37, 'Botble\\Blog\\Models\\Post', 7, 1, 'description', 'Create a brand that resonates with your audience. Explore strategies to develop a unique and memorable brand identity.', 'Tại HISOTECH, chúng tôi tin rằng dịch vụ khách hàng xuất sắc là nền tảng cho một trải nghiệm tuyệt vời. Là một startup công nghệ được thành lập vào năm 2020, chúng tôi cam kết hỗ trợ khách hàng ở mọi bước, đảm bảo nhu cầu của họ được đáp ứng với sự chuyên nghiệp, tận tâm, và hiệu quả.', '2025-04-14 03:58:28', '2025-04-14 03:58:28'),
(38, 'Botble\\Blog\\Models\\Post', 7, 1, 'image', 'news/7.jpg', 'news/2594-1.jpg', '2025-04-14 03:58:28', '2025-04-14 03:58:28'),
(39, 'Botble\\Blog\\Models\\Post', 8, 1, 'name', 'The Importance of Social Media Marketing for Businesses', 'Tối ưu hóa công nghệ – Tăng trưởng bền vững', '2025-04-14 04:06:26', '2025-04-14 04:06:26'),
(40, 'Botble\\Blog\\Models\\Post', 8, 1, 'description', 'Reach a wider audience and engage with potential customers. Discover the power of social media marketing for businesses.', 'DỊCH VỤ TƯ VẤN CÔNG NGHỆ - HISOTECH', '2025-04-14 04:06:26', '2025-04-14 04:06:26'),
(41, 'Botble\\Blog\\Models\\Post', 8, 1, 'image', 'news/8.jpg', 'news/19137-1.jpg', '2025-04-14 04:06:26', '2025-04-14 04:06:26'),
(42, 'Botble\\Blog\\Models\\Post', 9, 1, 'name', 'Content is King: Creating Engaging Content to Attract Customers', 'Công nghệ tài chính – Nâng tầm hiệu quả &amp; minh bạch tài chính doanh nghiệp', '2025-04-14 04:10:22', '2025-04-14 04:10:22'),
(43, 'Botble\\Blog\\Models\\Post', 9, 1, 'description', 'High-quality content is key to attracting and retaining customers. Explore strategies to create valuable and engaging content.', 'GIẢI PHÁP CÔNG NGHỆ TÀI CHÍNH - HISOTECH', '2025-04-14 04:10:22', '2025-04-14 04:10:22'),
(44, 'Botble\\Blog\\Models\\Post', 9, 1, 'image', 'news/9.jpg', 'news/1411-1.jpg', '2025-04-14 04:10:22', '2025-04-14 04:10:22'),
(45, 'Botble\\Blog\\Models\\Post', 1, 1, 'name', 'The Power of Networking: Building Relationships for Business Growth', 'Tăng tốc doanh số với giải pháp bán hàng thông minh', '2025-04-14 04:13:42', '2025-04-14 04:13:42'),
(46, 'Botble\\Blog\\Models\\Post', 1, 1, 'description', 'Learn how to build strategic connections and leverage your network to propel your business forward.', 'GIẢI PHÁP CÔNG NGHỆ BÁN HÀNG - HISOTECH', '2025-04-14 04:13:42', '2025-04-14 04:13:42'),
(47, 'Botble\\Blog\\Models\\Post', 1, 1, 'image', 'news/1.jpg', 'news/47160-1.jpg', '2025-04-14 04:13:42', '2025-04-14 04:13:42'),
(48, 'Botble\\Blog\\Models\\Post', 18, 1, 'name', 'Building a Sustainable Business: Environmental and Social Responsibility', 'Đổi mới để dẫn đầu – Công nghệ là chìa khóa của sáng tạo', '2025-04-14 04:17:44', '2025-04-14 04:17:44'),
(49, 'Botble\\Blog\\Models\\Post', 18, 1, 'description', 'Today\'s consumers are conscious. Learn how to build a sustainable business model that prioritizes social responsibility.', 'ĐỔI MỚI SÁNG TẠO – HISOTECH', '2025-04-14 04:17:44', '2025-04-14 04:17:44'),
