INSERT INTO `teams` (`id`, `name`, `photo`, `title`, `location`, `socials`, `status`, `created_at`, `updated_at`, `content`, `phone`, `email`, `address`, `website`, `description`) VALUES
(1, 'Hà Đại Dương', 'testimonials/87a5844e70b0691b67b0e1ad8b140baa.jpg', 'Technical Staff', 'VietNam', '{\"facebook\":\"https:\\/\\/www.facebook.com\\/duong.haha.100\",\"twitter\":\"https:\\/\\/twitter.com\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/\"}', 'published', '2024-12-09 00:01:21', '2025-06-07 08:42:39', '<p>Với tinh thần cầu tiến và chuyên môn vững vàng, anh Dương chịu trách nhiệm giám sát, bảo trì và hỗ trợ kỹ thuật cho các hệ thống vận hành của công ty. Anh luôn sẵn sàng giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo hiệu suất và độ tin cậy cao cho sản phẩm và dịch vụ mà chúng tôi cung cấp.</p>', '0973 73 56 79', 'vthadaiduong@gmail.com', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam', 'https://hisotechgroup.com/', 'Thực hiện kiểm tra, bảo trì, lắp đặt và sửa chữa hệ thống/sản phẩm kỹ thuật theo phân công.\nHỗ trợ kỹ thuật cho khách hàng, bộ phận kinh doanh hoặc sản xuất khi cần thiết.'),
(2, 'Phùng Quang Huy', 'testimonials/8e442450ef93d1f8db2e792d069abcb2.jpg', 'Chuyên viên kĩ thuật', 'VietNam', '{\"facebook\":\"https:\\/\\/www.facebook.com\\/am.hyu\",\"twitter\":\"https:\\/\\/twitter.com\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/_am.hy\\/\"}', 'published', '2024-12-09 00:01:21', '2025-06-07 08:42:05', '<p>Với tinh thần cầu tiến và chuyên môn vững vàng, anh Huy chịu trách nhiệm giám sát, bảo trì và hỗ trợ kỹ thuật cho các hệ thống vận hành của công ty. Anh luôn sẵn sàng giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo hiệu suất và độ tin cậy cao cho sản phẩm và dịch vụ mà chúng tôi cung cấp.</p>', '0343989940', 'huynut24@gmail.com', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam', 'https://hisotechgroup.com/', 'Thực hiện kiểm tra, bảo trì, lắp đặt và sửa chữa hệ thống/sản phẩm kỹ thuật theo phân công.\nHỗ trợ kỹ thuật cho khách hàng, bộ phận kinh doanh hoặc sản xuất khi cần thiết.'),
(9, 'Tăng Xuân Chiến', 'testimonials/84e466dc3240b2eb2b7c3b9d80c91bfd.jpg', 'Technical Staff', 'VietNam', '{\"facebook\":\"https:\\/\\/www.facebook.com\\/tangxchien\",\"twitter\":\"https:\\/\\/twitter.com\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/\"}', 'published', '2024-12-09 00:01:21', '2025-06-07 08:41:49', '<p>Với tinh thần cầu tiến và chuyên môn vững vàng, anh Chiến chịu trách nhiệm giám sát, bảo trì và hỗ trợ kỹ thuật cho các hệ thống vận hành của công ty. Anh luôn sẵn sàng giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo hiệu suất và độ tin cậy cao cho sản phẩm và dịch vụ mà chúng tôi cung cấp.</p>', '01123259241', 'tangxuanchien511@gmail.com', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam', 'https://hisotechgroup.com/', 'Thực hiện kiểm tra, bảo trì, lắp đặt và sửa chữa hệ thống/sản phẩm kỹ thuật theo phân công.\nHỗ trợ kỹ thuật cho khách hàng, bộ phận kinh doanh hoặc sản xuất khi cần thiết.'),
(10, 'Trần Minh An', 'testimonials/61fb1b58a88fec4d4f202d3e327631f2.jpg', 'Technical Staff', 'VietNam', '{\"facebook\":\"https:\\/\\/www.facebook.com\\/tran.an.435757\",\"twitter\":\"https:\\/\\/twitter.com\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/\"}', 'published', '2024-12-09 00:01:21', '2025-06-07 08:41:12', '<p>Với tinh thần cầu tiến và chuyên môn vững vàng, anh An chịu trách nhiệm giám sát, bảo trì và hỗ trợ kỹ thuật cho các hệ thống vận hành của công ty. Anh luôn sẵn sàng giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo hiệu suất và độ tin cậy cao cho sản phẩm và dịch vụ mà chúng tôi cung cấp.</p>', '01123259241', 'tranminhan23012003@gmail.com', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam', 'https://hisotechgroup.com/', 'Thực hiện kiểm tra, bảo trì, lắp đặt và sửa chữa hệ thống/sản phẩm kỹ thuật theo phân công.\nHỗ trợ kỹ thuật cho khách hàng, bộ phận kinh doanh hoặc sản xuất khi cần thiết.'),
(11, 'Nguyễn Tiến Dũng', '123fe298ce5fb2ec5dd3bbbb5e8b1d1c-copy.jpg', 'Technical Staff', 'VietNam', '{\"facebook\":\"https:\\/\\/www.facebook.com\\/dunglaanh23\",\"twitter\":\"https:\\/\\/twitter.com\\/\",\"instagram\":\"https:\\/\\/www.instagram.com\\/\"}', 'published', '2024-12-09 00:01:21', '2025-12-10 15:19:17', '<p>Với tinh thần cầu tiến và chuyên môn vững vàng, anh Dũng chịu trách nhiệm giám sát, bảo trì và hỗ trợ kỹ thuật cho các hệ thống vận hành của công ty. Anh luôn sẵn sàng giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo hiệu suất và độ tin cậy cao cho sản phẩm và dịch vụ mà chúng tôi cung cấp.</p>', '01123259241', 'ntd2002238@gmail.com', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam', 'https://hisotechgroup.com/', 'Thực hiện kiểm tra, bảo trì, lắp đặt và sửa chữa hệ thống/sản phẩm kỹ thuật theo phân công.\nHỗ trợ kỹ thuật cho khách hàng, bộ phận kinh doanh hoặc sản xuất khi cần thiết.');
