('en_US', 1, 'Ha Dai Duong', 'Technical Staff', 'VietNam', '<p>With a progressive spirit and solid expertise, Mr. Duong is responsible for monitoring, maintaining and providing technical support for the company\'s operating systems. He is always ready to solve technical problems quickly, ensuring high performance and reliability for the products and services we provide.</p>', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam'),
('en_US', 2, 'Phùng Quang Huy', 'Chuyên viên kĩ thuật', 'VietNam', '<p>With a progressive spirit and solid expertise, Mr. Huy is responsible for monitoring, maintaining and providing technical support for the company\'s operating systems. He is always ready to solve technical problems quickly, ensuring high performance and reliability for the products and services we provide.</p>', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam'),
('en_US', 9, 'Tang Xuan Chien', 'Technical Staff', 'VietNam', '<p>With a progressive spirit and solid expertise, Mr. Chien is responsible for monitoring, maintaining and providing technical support for the company\'s operating systems. He is always ready to solve technical problems quickly, ensuring high performance and reliability for the products and services we provide.</p>', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam'),
('en_US', 10, 'Tran Minh An', 'Technical Staff', 'VietNam', '<p>With a progressive spirit and solid expertise, Mr. An is responsible for monitoring, maintaining and providing technical support for the company\'s operating systems. He is always ready to solve technical problems quickly, ensuring high performance and reliability for the products and services we provide.</p>', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam'),
('en_US', 11, 'Nguyen Tien Dung', 'Technical Staff', 'VietNam', '<p>With a progressive spirit and solid expertise, Mr. Dung is responsible for monitoring, maintaining and providing technical support for the company\'s operating systems. He is always ready to solve technical problems quickly, ensuring high performance and reliability for the products and services we provide.</p>', 'Tòa C2 , D\'Capital , đường Trần Duy Hưng , phường Trung Hòa , quận Cầu Giấy, Hà Nội, Việt Nam');
INSERT INTO `testimonials` (`id`, `name`, `content`, `image`, `company`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Hà Phương Thảo', '<div>Hisotech thực sự ấn tượng! Cam kết của họ trong việc mang lại giải pháp công nghệ đáng tin cậy và sự hỗ trợ tận tâm đã giúp chúng tôi cải thiện hiệu suất vận hành đáng kể.</div>', 'pp1.jpg', 'Giám đốc điều hành', 'published', '2024-12-09 00:01:27', '2025-04-14 09:47:54'),
(2, 'Nguyễn Văn Minh', '<div>Hisotech đã vượt mong đợi của chúng tôi! Sự chuyên nghiệp và tốc độ phản hồi của họ giúp chúng tôi giải quyết các vấn đề kỹ thuật một cách nhanh chóng, đảm bảo dự án hoàn thành đúng tiến độ.</div>', 'pp2.jpg', 'Trưởng bộ phận SEO', 'published', '2024-12-09 00:01:27', '2025-04-14 09:33:45'),
(3, 'Trần Bảo Châu', '<div>Chúng tôi rất hài lòng với dịch vụ của Hisotech! Sự am hiểu sâu sắc về công nghệ và cách tiếp cận linh hoạt của họ đã giúp chúng tôi tối ưu hóa quy trình vận hành một cách hiệu quả.</div>', 'pp4.jpg', 'Giám đốc công ty', 'published', '2024-12-09 00:01:27', '2025-04-14 09:34:15'),
(4, 'Lê Thành', '<div>Hợp tác với Hisotech là một trải nghiệm tuyệt vời! Đội ngũ của họ luôn sáng tạo và tận tâm, mang đến các giải pháp công nghệ phù hợp, giúp doanh nghiệp chúng tôi phát triển mạnh mẽ hơn.</div>', 'pp2.jpg', 'Giám đốc điều hành, Bank of America', 'published', '2024-12-09 00:01:27', '2025-04-14 11:27:24');
INSERT INTO `testimonials_translations` (`lang_code`, `testimonials_id`, `name`, `content`, `company`) VALUES
('en_US', 1, 'Ha Phuong Thao', '<div>Hisotech is truly impressive! Their commitment to providing reliable technology solutions and dedicated support has helped us improve our operational performance significantly.</div>', 'CEO'),
('en_US', 2, 'Nguyen Van Minh', '<div>Hisotech exceeded our expectations! Their professionalism and speed of response helped us resolve technical issues quickly, ensuring the project was completed on schedule.</div>', 'Head of SEO'),
('en_US', 3, 'Tran Bao Chau', '<div>We are very satisfied with Hisotech\'s service! Their deep understanding of technology and flexible approach have helped us optimize our operations efficiently.</div>', 'Company Director'),
('en_US', 4, 'Le Thanh', '<div>Working with Hisotech has been a great experience! Their team is innovative and dedicated, providing the right technology solutions that help our business grow stronger.</div>', 'CEO, Bank of America');
